import{_ as i,c as a,o as e,ah as h}from"./chunks/framework.DwHsq7Fg.js";const o=JSON.parse('{"title":"Основы Docker: Docker Swarm","description":"","frontmatter":{},"headers":[],"relativePath":"basic_docker/docker_swarm.md","filePath":"basic_docker/docker_swarm.md"}'),k={name:"basic_docker/docker_swarm.md"};function l(t,s,n,r,p,d){return e(),a("div",null,s[0]||(s[0]=[h(`<h1 id="основы-docker-docker-swarm" tabindex="-1">Основы Docker: Docker Swarm <a class="header-anchor" href="#основы-docker-docker-swarm" aria-label="Permalink to “Основы Docker: Docker Swarm”">​</a></h1><p><strong>Docker Swarm</strong> — это собственное решение Docker для кластеризации и оркестрации контейнеров. Оно позволяет управлять группой Docker-хостов (называемых узлами) как единой виртуальной системой. Swarm предоставляет такие возможности, как масштабирование, обнаружение сервисов, балансировка нагрузки и отказоустойчивость для контейнеризованных приложений.</p><h2 id="основные-понятия-docker-swarm" tabindex="-1">Основные понятия Docker Swarm <a class="header-anchor" href="#основные-понятия-docker-swarm" aria-label="Permalink to “Основные понятия Docker Swarm”">​</a></h2><ul><li><strong>Узел (Node):</strong> Экземпляр Docker-движка, участвующий в swarm-кластере. Узлы могут быть менеджерами или рабочими.</li><li><strong>Менеджер (Manager Node):</strong> Узел, отвечающий за управление swarm-кластером, оркестрацию сервисов, распределение задач между рабочими узлами и поддержание желаемого состояния кластера. Рекомендуется иметь несколько менеджеров для обеспечения отказоустойчивости.</li><li><strong>Рабочий (Worker Node):</strong> Узел, выполняющий контейнеры (задачи), назначенные менеджерами.</li><li><strong>Сервис (Service):</strong> Определение задачи, которую необходимо выполнить в swarm. Сервис описывает, какой образ контейнера использовать, сколько реплик (экземпляров) запустить, какие сети и тома использовать и т.д.</li><li><strong>Задача (Task):</strong> Конкретный экземпляр контейнера, выполняющийся в рамках сервиса. Менеджер распределяет задачи между рабочими узлами.</li><li><strong>Оркестрация (Orchestration):</strong> Автоматическое управление жизненным циклом контейнеров и сервисов для поддержания желаемого состояния приложения.</li><li><strong>Обнаружение сервисов (Service Discovery):</strong> Автоматическое обнаружение сетевых адресов сервисов внутри swarm-кластера.</li><li><strong>Балансировка нагрузки (Load Balancing):</strong> Распределение входящего трафика между репликами сервиса.</li></ul><h2 id="инициализация-swarm-кластера" tabindex="-1">Инициализация Swarm-кластера <a class="header-anchor" href="#инициализация-swarm-кластера" aria-label="Permalink to “Инициализация Swarm-кластера”">​</a></h2><p>Первым шагом является инициализация swarm-кластера на одном из ваших Docker-хостов (который станет менеджером). Используйте команду <code>docker swarm init</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swarm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --advertise-addr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-адрес_или_интерфейс_менеджер</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p><code>--advertise-addr</code> указывает IP-адрес или сетевой интерфейс, который другие узлы будут использовать для связи с менеджером.</p><p>После успешной инициализации менеджер выведет команду, которую необходимо выполнить на рабочих узлах для присоединения к swarm-кластеру. Эта команда будет содержать токен.</p><h2 id="присоединение-узлов-к-swarm-кластеру" tabindex="-1">Присоединение узлов к Swarm-кластеру <a class="header-anchor" href="#присоединение-узлов-к-swarm-кластеру" aria-label="Permalink to “Присоединение узлов к Swarm-кластеру”">​</a></h2><h3 id="присоединение-рабочего-узла" tabindex="-1">Присоединение рабочего узла <a class="header-anchor" href="#присоединение-рабочего-узла" aria-label="Permalink to “Присоединение рабочего узла”">​</a></h3><p>На рабочем узле выполните команду, полученную от менеджера (она будет выглядеть примерно так):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swarm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> join</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SWMTKN-1-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx-yyyyyyyyyyyyyyyyyyyyyyyyyyyyyyyy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-адрес_или_хост_менеджер</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:2377</span></span></code></pre></div><h3 id="присоединение-менеджера-для-обеспечения-отказоустоичивости" tabindex="-1">Присоединение менеджера (для обеспечения отказоустойчивости) <a class="header-anchor" href="#присоединение-менеджера-для-обеспечения-отказоустоичивости" aria-label="Permalink to “Присоединение менеджера (для обеспечения отказоустойчивости)”">​</a></h3><p>Чтобы добавить еще один менеджер в swarm-кластер (рекомендуется для отказоустойчивости), выполните на другом Docker-хосте команду, полученную от первого менеджера (она будет выглядеть примерно так):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swarm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> join</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SWMTKN-1-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx-zzzzzzzzzzzzzzzzzzzzzzzzzzzzzzzz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --manager-advertise-addr</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-адрес_или_интерфейс_нового_менеджер</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:2377</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-адрес_или_хост_существующего_менеджер</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:2377</span></span></code></pre></div><p><code>--manager-advertise-addr</code> указывает IP-адрес или интерфейс нового менеджера для связи с другими менеджерами.</p><h2 id="управление-узлами-swarm-кластера" tabindex="-1">Управление узлами Swarm-кластера <a class="header-anchor" href="#управление-узлами-swarm-кластера" aria-label="Permalink to “Управление узлами Swarm-кластера”">​</a></h2><p>Вы можете управлять узлами swarm-кластера с менеджера с помощью команды <code>docker node</code>.</p><h3 id="просмотр-списка-узлов" tabindex="-1">Просмотр списка узлов <a class="header-anchor" href="#просмотр-списка-узлов" aria-label="Permalink to “Просмотр списка узлов”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Эта команда выведет список всех узлов в кластере, их ID, статус, доступность, роль (manager или worker) и версию Docker Engine.</p><h3 id="информация-об-узле" tabindex="-1">Информация об узле <a class="header-anchor" href="#информация-об-узле" aria-label="Permalink to “Информация об узле”">​</a></h3><p>Чтобы получить подробную информацию о конкретном узле, используйте команду <code>docker node inspect</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="обновление-узла" tabindex="-1">Обновление узла <a class="header-anchor" href="#обновление-узла" aria-label="Permalink to “Обновление узла”">​</a></h3><p>Вы можете обновлять свойства узла, такие как его роль или доступность:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --role</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> worker</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Изменить роль на worker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --availability</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> drain</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Перевести узел в состояние drain (не назначать новые задачи)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --availability</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> active</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Вернуть узел в активное состояние</span></span></code></pre></div><h3 id="удаление-узла-из-кластера" tabindex="-1">Удаление узла из кластера <a class="header-anchor" href="#удаление-узла-из-кластера" aria-label="Permalink to “Удаление узла из кластера”">​</a></h3><p>Чтобы удалить узел из swarm-кластера:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Удаление с менеджера (рабочий узел должен покинуть кластер командой docker swarm leave)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_узл</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Принудительное удаление (если узел недоступен)</span></span></code></pre></div><p>На рабочем узле для выхода из кластера используется команда <code>docker swarm leave</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swarm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leave</span></span></code></pre></div><p>На менеджере для принудительного выхода (если узел недоступен):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swarm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> leave</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div><h2 id="развертывание-сервисов-в-swarm-кластере" tabindex="-1">Развертывание сервисов в Swarm-кластере <a class="header-anchor" href="#развертывание-сервисов-в-swarm-кластере" aria-label="Permalink to “Развертывание сервисов в Swarm-кластере”">​</a></h2><p>Для развертывания приложений в swarm-кластере используются сервисы. Сервисы определяют, какие контейнеры запускать и как они должны работать. Сервисы управляются менеджерами.</p><h3 id="создание-сервиса" tabindex="-1">Создание сервиса <a class="header-anchor" href="#создание-сервиса" aria-label="Permalink to “Создание сервиса”">​</a></h3><p>Сервисы создаются с помощью команды <code>docker service create</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 80:80</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --replicas</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:latest</span></span></code></pre></div><ul><li><code>--name my-web</code>: Имя сервиса.</li><li><code>--publish 80:80</code>: Публикация порта 80 контейнера на порт 80 любого узла в кластере (Swarm автоматически маршрутизирует трафик).</li><li><code>--replicas 3</code>: Желаемое количество реплик (экземпляров) контейнера. Swarm будет поддерживать это количество, автоматически перезапуская отказавшие контейнеры и распределяя их по доступным рабочим узлам.</li><li><code>nginx:latest</code>: Образ Docker, который будет использоваться для контейнеров сервиса.</li></ul><h3 id="просмотр-списка-сервисов" tabindex="-1">Просмотр списка сервисов <a class="header-anchor" href="#просмотр-списка-сервисов" aria-label="Permalink to “Просмотр списка сервисов”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Эта команда выведет список всех запущенных сервисов, их ID, имена, количество реплик, образ и порты.</p><h3 id="информация-о-сервисе" tabindex="-1">Информация о сервисе <a class="header-anchor" href="#информация-о-сервисе" aria-label="Permalink to “Информация о сервисе”">​</a></h3><p>Чтобы получить подробную информацию о конкретном сервисе, используйте команду <code>docker service inspect</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ID_или_имя_сервис</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">а</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h3 id="масштабирование-сервиса" tabindex="-1">Масштабирование сервиса <a class="header-anchor" href="#масштабирование-сервиса" aria-label="Permalink to “Масштабирование сервиса”">​</a></h3><p>Вы можете изменять количество реплик сервиса для масштабирования приложения:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scale</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span></span></code></pre></div><p>Эта команда увеличит количество реплик сервиса <code>my-web</code> до 5. Swarm автоматически запустит дополнительные контейнеры на доступных рабочих узлах.</p><h3 id="обновление-сервиса" tabindex="-1">Обновление сервиса <a class="header-anchor" href="#обновление-сервиса" aria-label="Permalink to “Обновление сервиса”">​</a></h3><p>Вы можете обновлять различные параметры сервиса, такие как образ, порты, переменные окружения и количество реплик:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx:1.21</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Обновление образа</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8080:80</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Изменение опубликованного порта</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NEW_VAR=value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Добавление переменной окружения</span></span></code></pre></div><p>Обновления сервисов выполняются постепенно (rolling updates) по умолчанию, чтобы обеспечить непрерывную доступность приложения.</p><h3 id="просмотр-задач-сервиса" tabindex="-1">Просмотр задач сервиса <a class="header-anchor" href="#просмотр-задач-сервиса" aria-label="Permalink to “Просмотр задач сервиса”">​</a></h3><p>Чтобы увидеть список задач (контейнеров), выполняющихся в рамках сервиса, используйте команду <code>docker service ps</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span></span></code></pre></div><p>Эта команда покажет ID задачи, имя сервиса, желаемое и текущее состояние, ошибки (если есть) и узел, на котором выполняется задача.</p><h3 id="удаление-сервиса" tabindex="-1">Удаление сервиса <a class="header-anchor" href="#удаление-сервиса" aria-label="Permalink to “Удаление сервиса”">​</a></h3><p>Чтобы удалить сервис и все его задачи, используйте команду <code>docker service rm</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-web</span></span></code></pre></div><h2 id="сети-и-тома-в-swarm-кластере" tabindex="-1">Сети и тома в Swarm-кластере <a class="header-anchor" href="#сети-и-тома-в-swarm-кластере" aria-label="Permalink to “Сети и тома в Swarm-кластере”">​</a></h2><h3 id="сети" tabindex="-1">Сети <a class="header-anchor" href="#сети" aria-label="Permalink to “Сети”">​</a></h3><p>В Docker Swarm используются <strong>overlay networks</strong> для обеспечения взаимодействия между сервисами, работающими на разных узлах кластера. Вы можете создавать overlay-сети с помощью команды <code>docker network create -d overlay &lt;имя_сети&gt;</code>. Контейнеры сервисов, подключенные к одной overlay-сети, могут взаимодействовать друг с другом по именам сервисов (DNS-разрешение имен).</p><h3 id="тома" tabindex="-1">Тома <a class="header-anchor" href="#тома" aria-label="Permalink to “Тома”">​</a></h3><p>Для хранения постоянных данных в Swarm используются <strong>managed volumes</strong>. Вы можете создавать тома, которые будут доступны для сервисов в кластере. Docker Swarm обеспечивает согласованность данных при использовании томов. Тома создаются с помощью команды <code>docker volume create --driver local &lt;имя_тома&gt;</code> (по умолчанию локальные тома) или с использованием сторонних драйверов томов, поддерживающих кластеризацию.</p><p>При определении сервисов вы можете монтировать тома в контейнеры.</p><h2 id="docker-compose-и-swarm" tabindex="-1">Docker Compose и Swarm <a class="header-anchor" href="#docker-compose-и-swarm" aria-label="Permalink to “Docker Compose и Swarm”">​</a></h2><p>Вы также можете использовать файлы <code>docker-compose.yml</code> для определения сервисов и развертывания их в Swarm-кластере с помощью команды <code>docker stack deploy</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deploy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --compose-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-stack</span></span></code></pre></div><p><code>my-stack</code> — это имя развертывания (stack). Docker Compose преобразует определения сервисов из файла <code>docker-compose.yml</code> в сервисы Swarm.</p><p>Управление развернутыми стеками осуществляется с помощью команды <code>docker stack</code>.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # Просмотр списка развертываний</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-stack</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Просмотр задач стека</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-stack</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Удаление развертывания</span></span></code></pre></div><h2 id="преимущества-docker-swarm" tabindex="-1">Преимущества Docker Swarm <a class="header-anchor" href="#преимущества-docker-swarm" aria-label="Permalink to “Преимущества Docker Swarm”">​</a></h2><ul><li><strong>Простота использования:</strong> Легко настроить и управлять кластером с помощью Docker CLI.</li><li><strong>Масштабируемость:</strong> Легко масштабировать приложения, увеличивая или уменьшая количество реплик сервисов.</li><li><strong>Отказоустойчивость:</strong> Swarm автоматически поддерживает желаемое количество реплик и перераспределяет задачи при отказе узлов.</li><li><strong>Обнаружение сервисов и балансировка нагрузки:</strong> Встроенные механизмы для обнаружения сервисов и распределения трафика.</li><li><strong>Интеграция с Docker:</strong> Полностью интегрирован с Docker Engine и Docker CLI.</li></ul><p>Docker Swarm является мощным инструментом для оркестрации контейнеров, особенно для небольших и средних кластеров, где простота настройки и использования являются приоритетом. Для более сложных сценариев оркестрации с расширенными возможностями может потребоваться использование более продвинутых инструментов, таких как Kubernetes.</p>`,77)]))}const c=i(k,[["render",l]]);export{o as __pageData,c as default};
